const e=JSON.parse('{"key":"v-033b8d70","path":"/tech/redis/%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%8401-%E6%99%AE%E9%80%9A%E9%93%BE%E8%A1%A8.html","title":"数据结构01-普通链表","lang":"zh-CN","frontmatter":{"date":"2021-12-06T22:11:00.000Z","category":["Redis"],"tag":["Redis","算法"],"description":"数据结构01-普通链表 基础知识 链表是比较常用的一个数据结构，在JAVA中的实现是LinkedList，但是在C的标准库中并没有内置的链表可供使用，所以redis实现了一套。我们知道数组的内存地址是连续的，最大的特征是支持随机访问，所以数组的读时间复杂度是O(1)，但是在写的场景时间复杂度是O(N)，在某个位置插入一条数据，需要把这个位置后的所有数据向后移动一位，在内存不足时还需要重新申请内存。 而链表的内存结构是不连续的，不支持随机访问，当需要读取某个位置的数据时，需要从头遍历到尾部才能实现，所有读是O(N)；对链表写入操作时，因为两个节点的内存都是独立不连续的，在这中间插入数据的时候，只要把next、prev指针重新指向即可，所以写是O(1)。这就是数组和链表的基础知识，我们看下在redis中的具体实现是怎么样的吧！","head":[["meta",{"property":"og:url","content":"https://dhbin.cn/tech/redis/%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%8401-%E6%99%AE%E9%80%9A%E9%93%BE%E8%A1%A8.html"}],["meta",{"property":"og:site_name","content":"DHB"}],["meta",{"property":"og:title","content":"数据结构01-普通链表"}],["meta",{"property":"og:description","content":"数据结构01-普通链表 基础知识 链表是比较常用的一个数据结构，在JAVA中的实现是LinkedList，但是在C的标准库中并没有内置的链表可供使用，所以redis实现了一套。我们知道数组的内存地址是连续的，最大的特征是支持随机访问，所以数组的读时间复杂度是O(1)，但是在写的场景时间复杂度是O(N)，在某个位置插入一条数据，需要把这个位置后的所有数据向后移动一位，在内存不足时还需要重新申请内存。 而链表的内存结构是不连续的，不支持随机访问，当需要读取某个位置的数据时，需要从头遍历到尾部才能实现，所有读是O(N)；对链表写入操作时，因为两个节点的内存都是独立不连续的，在这中间插入数据的时候，只要把next、prev指针重新指向即可，所以写是O(1)。这就是数组和链表的基础知识，我们看下在redis中的具体实现是怎么样的吧！"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-23T12:17:45.000Z"}],["meta",{"property":"article:author","content":"DHB"}],["meta",{"property":"article:tag","content":"Redis"}],["meta",{"property":"article:tag","content":"算法"}],["meta",{"property":"article:published_time","content":"2021-12-06T22:11:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-23T12:17:45.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"数据结构01-普通链表\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2021-12-06T22:11:00.000Z\\",\\"dateModified\\":\\"2023-03-23T12:17:45.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"DHB\\",\\"url\\":\\"https://dhbin.cn\\"}]}"]]},"headers":[{"level":2,"title":"基础知识","slug":"基础知识","link":"#基础知识","children":[]},{"level":2,"title":"普通链表","slug":"普通链表","link":"#普通链表","children":[{"level":3,"title":"redis中链表实现","slug":"redis中链表实现","link":"#redis中链表实现","children":[]},{"level":3,"title":"创建链表","slug":"创建链表","link":"#创建链表","children":[]},{"level":3,"title":"清空链表","slug":"清空链表","link":"#清空链表","children":[]},{"level":3,"title":"头部插入","slug":"头部插入","link":"#头部插入","children":[]},{"level":3,"title":"尾部插入","slug":"尾部插入","link":"#尾部插入","children":[]},{"level":3,"title":"链表查找","slug":"链表查找","link":"#链表查找","children":[]},{"level":3,"title":"使用建议","slug":"使用建议","link":"#使用建议","children":[]}]},{"level":2,"title":"快速链表","slug":"快速链表","link":"#快速链表","children":[]}],"git":{"createdTime":1679573865000,"updatedTime":1679573865000,"contributors":[{"name":"dhb","email":"xx158@qq.com","commits":1}]},"readingTime":{"minutes":4.62,"words":1387},"filePathRelative":"tech/redis/数据结构01-普通链表.md","localizedDate":"2021年12月6日","excerpt":"<h1> 数据结构01-普通链表</h1>\\n<h2> 基础知识</h2>\\n<p>链表是比较常用的一个数据结构，在JAVA中的实现是LinkedList，但是在C的标准库中并没有内置的链表可供使用，所以redis实现了一套。我们知道数组的内存地址是连续的，最大的特征是支持随机访问，所以数组的读时间复杂度是O(1)，但是在写的场景时间复杂度是O(N)，在某个位置插入一条数据，需要把这个位置后的所有数据向后移动一位，在内存不足时还需要重新申请内存。</p>\\n<p>而链表的内存结构是不连续的，不支持随机访问，当需要读取某个位置的数据时，需要从头遍历到尾部才能实现，所有读是O(N)；对链表写入操作时，因为两个节点的内存都是独立不连续的，在这中间插入数据的时候，只要把next、prev指针重新指向即可，所以写是O(1)。这就是数组和链表的基础知识，我们看下在redis中的具体实现是怎么样的吧！</p>","autoDesc":true}');export{e as data};
